add_action( 'wp_footer', function () {
	$js = <<<'JS'
/* Accessibility fixes (server-rendered elements exist before this footer script runs).
 * Each fix is guarded so it never overwrites an existing author value. */
(function () {
  function label(sel, text) {
    document.querySelectorAll(sel).forEach(function (el) {
      if (el && !el.getAttribute('aria-label') && !el.getAttribute('aria-labelledby')) {
        el.setAttribute('aria-label', text);
      }
    });
  }
  /* #5 landmark-unique: give each <nav> a distinct accessible name */
  label('#site-navigation', 'Primary');
  label('#mainnav', 'Primary mobile');
  label('.player-panels-nav', 'Podcast subscribe and share');

  /* #2 label-title-only: SSP player inputs carry only a title attribute. Mirror it into
   * aria-label so the accessible name is reliable (title alone is not). */
  document.querySelectorAll('.castos-player input[title]').forEach(function (el) {
    if (!el.getAttribute('aria-label') && !el.getAttribute('aria-labelledby')) {
      var t = el.getAttribute('title');
      if (t) el.setAttribute('aria-label', t);
    }
  });

  /* #6 landmark-complementary-is-top-level: SSP wraps the episode meta line in a bare <aside>,
   * which implies role=complementary nested inside <main>. It is just episode metadata, not a
   * page-level aside, so drop the misplaced landmark role. Also covers the widget-sidebar
   * <aside> widgets on the Episode List page ("/podcast/"), which nest inside the #secondary
   * complementary region and were flagged the same way. */
  document.querySelectorAll('.podcast_meta aside, .podcast_player aside, #secondary aside').forEach(function (el) {
    if (!el.getAttribute('role')) el.setAttribute('role', 'presentation');
  });

  /* landmark-unique (Episode List page, "/podcast/"): SSP hardcodes the same aria-label
   * ("Podcast player" on the player region, "Podcast subscribe and share" on its nav) into
   * every player instance. That's fine when a page has one player, but the Episode List
   * template renders one full player per episode, so the labels collide. When more than one
   * element shares a landmark role + identical label, append that instance's episode title
   * (or a 1-based index as a fallback) so each is uniquely identifiable. */
  function uniquifyLandmarks(sel) {
    var groups = {};
    document.querySelectorAll(sel).forEach(function (el) {
      var lbl = el.getAttribute('aria-label') || '';
      (groups[lbl] = groups[lbl] || []).push(el);
    });
    Object.keys(groups).forEach(function (lbl) {
      var els = groups[lbl];
      if (!lbl || els.length < 2) return;
      els.forEach(function (el, i) {
        var container = el.closest('.castos-player') || el;
        var t = container.querySelector('.episode-title, .ssp-episode-title, .player__episode-title');
        var suffix = (t && t.textContent.trim()) ? t.textContent.trim() : String(i + 1);
        el.setAttribute('aria-label', lbl + ' – ' + suffix);
      });
    });
  }
  uniquifyLandmarks('[role="region"].castos-player');
  uniquifyLandmarks('.player-panels-nav');

  /* Pending #1 (WCAG 2.1.1 Keyboard): the Castos player's seek bar is a div[role="progressbar"]
   * with no tabindex — so it can never receive keyboard focus. SSP's own castos-player.min.js
   * already contains ArrowLeft/ArrowRight keydown handling for this element (dead code, since a
   * non-focusable div never fires keydown), so the actual fix is just to make it focusable with
   * the correct interactive role — SSP's existing handler does the rest. */
  document.querySelectorAll('.ssp-progress[role="progressbar"]').forEach(function (bar) {
    bar.setAttribute('role', 'slider');
    bar.setAttribute('tabindex', '0');
    if (!bar.getAttribute('aria-label') && !bar.getAttribute('aria-labelledby')) {
      bar.setAttribute('aria-label', 'Seek');
    }
  });

  /* NOTE: #3 (aria-label on role-less div) and #4 (h3->h2 heading order) are ALSO W3C static-HTML
   * errors, so they are fixed server-side in the companion snippet "Accessibility: server-side
   * markup fixes (W3C)" — not here — so both WAVE and the W3C validator pass. */
})();
JS;
	echo "\n<script id=\"a11y-fixes\">" . $js . "</script>\n";
}, 99 );

add_action( 'template_redirect', function () {
	// Only buffer normal front-end HTML page requests.
	if ( is_admin() || is_feed() || is_embed() || is_404()
		|| wp_doing_ajax()
		|| ( defined( 'REST_REQUEST' ) && REST_REQUEST )
		|| ( defined( 'DOING_CRON' ) && DOING_CRON ) ) {
		return;
	}

	ob_start( function ( $html ) {
		// Guard: only touch full HTML documents.
		if ( ! is_string( $html ) || stripos( $html, '</html>' ) === false ) {
			return $html;
		}

		// #3 aria-prohibited-attr: remove aria-label from role-less .player-panel-row <div>s.
		$html = preg_replace_callback(
			'/<div\b[^>]*\bclass="[^"]*\bplayer-panel-row\b[^"]*"[^>]*>/i',
			function ( $m ) {
				if ( preg_match( '/\brole\s*=/i', $m[0] ) ) {
					return $m[0]; // has a role -> aria-label is allowed, leave it
				}
				return preg_replace( '/\s+aria-label="[^"]*"/i', '', $m[0] );
			},
			$html
		);

		// #4 heading-order: promote SSP featured-player title from <h3> to <h2>
		// (it follows the page <h1> and otherwise skips a level).
		$html = preg_replace(
			'/<h3(\s[^>]*\bclass="[^"]*\bssp-episode-title\b[^"]*"[^>]*)>(.*?)<\/h3>/is',
			'<h2$1>$2</h2>',
			$html
		);

		return $html;
	} );
}, 0 );

add_filter( 'sydney_custom_css', function ( $css ) {
	if ( ! is_string( $css ) || '' === $css ) {
		return $css;
	}
	// Sydney emits declarations with no value when a Customizer option is blank, e.g.
	// "color:;" or "background-color: ;" — drop those (they are W3C "Parse Error"s).
	$css = preg_replace( '/[A-Za-z-]+\s*:\s*;/', '', $css );
	// Same, but where the empty declaration is the last in a rule (no ';', ends at '}'): "{color:}".
	$css = preg_replace( '/[A-Za-z-]+\s*:\s*(?=\})/', '', $css );
	// Bare-unit lengths with no number, e.g. "letter-spacing:px;".
	$css = preg_replace( '/[A-Za-z-]+\s*:\s*(?:px|em|rem|ex|ch|vw|vh|vmin|vmax|%)\s*;/i', '', $css );
	// Invalid keyword "regular" from a font option ("font-weight:regular" is not a CSS value;
	// browsers ignore it, so removing it changes nothing visually).
	$css = preg_replace( '/font-weight\s*:\s*regular\s*;?/i', '', $css );
	return $css;
}, 99 );

add_action( 'template_redirect', function () {
	if ( is_admin() || is_feed() || is_embed() || is_404()
		|| wp_doing_ajax()
		|| ( defined( 'REST_REQUEST' ) && REST_REQUEST )
		|| ( defined( 'DOING_CRON' ) && DOING_CRON ) ) {
		return;
	}
	ob_start( function ( $html ) {
		if ( ! is_string( $html ) || stripos( $html, '</html>' ) === false ) {
			return $html;
		}
		$html = preg_replace_callback( '/\shref="([^"]*\s[^"]*)"/i', function ( $m ) {
			return ' href="' . str_replace( ' ', '%20', $m[1] ) . '"';
		}, $html );
		$html = preg_replace_callback( '/<button\b[^>]*>/i', function ( $m ) {
			return preg_replace( '/\s+readonly(=(["\'])[^"\']*\2)?/i', '', $m[0] );
		}, $html );
		$html = preg_replace( '/\s+on="tap:[^"]*"/i', '', $html );
		$html = preg_replace_callback( '/<input\b[^>]*\bclass="[^"]*\binput-embed\b[^"]*"[^>]*>/i', function ( $m ) {
			return preg_replace( '/[\r\n]+/', ' ', $m[0] );
		}, $html );
		$html = preg_replace( '/(<\/aside>\s*<\/div>)\s*<\/p>/i', '$1', $html );
		$parts = preg_split( '/(<\/head>)/i', $html, 2, PREG_SPLIT_DELIM_CAPTURE );
		if ( 3 === count( $parts ) ) {
			$moved = '';
			$parts[2] = preg_replace_callback( '/<style\b[^>]*>(.*?)<\/style>/is', function ( $m ) use ( &$moved ) {
				if ( strpos( $m[1], '--ssp-episode-list' ) !== false || strpos( $m[1], '--wpforms-' ) !== false ) {
					$moved .= $m[0];
					return '';
				}
				return $m[0];
			}, $parts[2] );
			if ( '' !== $moved ) {
				$html = $parts[0] . $moved . $parts[1] . $parts[2];
			}
		}

		// W3C info/warning: redundant "type" attribute on <script> tags (unnecessary for JS
		// resources in HTML5). Found on CookieYes's injected <script id="cookieyes" ...> tag.
		$html = preg_replace_callback( '/<script\b[^>]*>/i', function ( $m ) {
			return preg_replace( '/\s+type=(["\'])text\/javascript\1/i', '', $m[0] );
		}, $html );

		// W3C info/warning: redundant role="main" on the <main> element (the role is already
		// implicit on <main> in HTML5).
		$html = preg_replace_callback( '/<main\b[^>]*>/i', function ( $m ) {
			return preg_replace( '/\s+role=(["\'])main\1/i', '', $m[0] );
		}, $html );

		// W3C info: trailing slash on void elements has no effect in HTML5 and is flagged as
		// noise. Strip it from any void element's self-closing form site-wide (safe: void
		// elements never have a closing tag either way, so this changes nothing but the markup).
		$html = preg_replace(
			'/(<(?:area|base|br|col|embed|hr|img|input|link|meta|param|source|track|wbr)\b[^>]*?)\s*\/>/i',
			'$1>',
			$html
		);

		return $html;
	} );
}, 0 );

add_action( 'wp_footer', function () {
    ?>
<script id="a11y-redundant-link-title-fix">
(function () {
  function findItemAncestor(el) {
    var node = el;
    for (var i = 0; i < 6 && node; i++) {
      if (node.tagName === 'LI' || node.tagName === 'ARTICLE') return node;
      node = node.parentElement;
    }
    return null;
  }

  function isRedundantTitle(el) {
    var title = (el.getAttribute('title') || '').trim();
    if (!title) return false;
    var al = (el.getAttribute('aria-label') || '').trim();
    if (al && title.toLowerCase() === al.toLowerCase()) return true;
    var ownText;
    if (el.tagName === 'IMG') {
      ownText = (el.getAttribute('alt') || '').trim();
    } else {
      var img = el.querySelector('img[alt]');
      ownText = img ? (img.getAttribute('alt') || '').trim() : (el.textContent || '').trim();
    }
    return !!(ownText && title.toLowerCase() === ownText.toLowerCase());
  }

  function run() {
    // Redundant title text: title duplicates the element's own accessible name
    // (aria-label, own text, own alt, or a child img's alt). Covers links, buttons, inputs,
    // and bare images (e.g. SSP's Subscribe/Share buttons, share-icon links labelled via
    // aria-label, the RSS/Episode-URL/Embed-code fields whose aria-label was mirrored from
    // title by the companion "landmarks, labels & ARIA" snippet, and podcast artwork <img>
    // tags carrying an identical title+alt).
    document.querySelectorAll('a[title], button[title], input[title], img[title]').forEach(function (el) {
      if (isRedundantTitle(el)) el.removeAttribute('title');
    });

    // Redundant link: an image-only link duplicating a nearby text link to the same URL
    document.querySelectorAll('a[href] > img:only-child').forEach(function (img) {
      var a = img.parentElement;
      if ((a.textContent || '').trim() !== '') return;
      var item = findItemAncestor(a);
      if (!item) return;
      var alt = (img.getAttribute('alt') || '').trim().toLowerCase();
      if (!alt) return;
      var href = a.getAttribute('href');
      if (!href) return;
      var candidates = item.querySelectorAll('a[href="' + href.replace(/"/g, '\\"') + '"]');
      candidates.forEach(function (b) {
        if (b === a) return;
        var btext = (b.textContent || '').trim().toLowerCase();
        if (btext && (btext === alt || alt.indexOf(btext) !== -1 || btext.indexOf(alt) !== -1)) {
          a.setAttribute('aria-hidden', 'true');
          a.setAttribute('tabindex', '-1');
        }
      });
    });
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', run); else run();
})();
</script>
    <?php
}, 99 );
